const updatePlayerDropdown = () => {
    if (typeof document === "undefined") return; // headless host: no DOM dropdowns
    const playerSelect = document.getElementById('playerID');
    if (!playerSelect) return;

    const buildOptions = (select, withEveryone = false) => {
        select.innerHTML = withEveryone
            ? '<option value="all">⭐ Everyone</option>'
            : '<option value="" disabled selected>Select a player</option>';
        for (let ship of game.ships) {
            const option = document.createElement('option');
            option.value = ship.id;
            option.textContent = `${ship.id} | ${ship.name}`;
            select.appendChild(option);
        }
    };

    buildOptions(playerSelect, true);

    const duel1Select = document.getElementById('duelPlayer1ID');
    const duel2Select = document.getElementById('duelPlayer2ID');
    if (duel1Select) buildOptions(duel1Select);
    if (duel2Select) buildOptions(duel2Select);
};

const updateBannedDropdown = () => {
    if (typeof document === "undefined") return; // headless host: no DOM dropdowns
    const bannedSelect = document.getElementById('bannedPlayerID');
    bannedSelect.innerHTML = '<option value="" disabled selected>Select a banned player</option>'; 
	
    sessionMemory.banned.forEach((name, index) => {
        const option = document.createElement('option');
        option.value = index; 
        option.textContent = name;
        bannedSelect.appendChild(option);
    });
};

