const customEvent = (eventName) => {
    switch (eventName) {
        case "ship_left":
            recalculateTickDelay();
            updateScoreboard();
			updatePlayerDropdown();
            // If a duel participant left (vs. died), end the duel so others aren't
            // stuck force-spectating forever.
            if (_currentDuelState.active && _currentDuelState.players.some(id => !shipByID(id))) {
                stopRankedDuel();
            }
            break
    }
}

// ===== Access-code verification (replaces the captcha) =====
// Flow: ship_spawned -> CodeVerify.initiate (freeze on spectator + open keyboard) ->
// player types code -> _kbCommit("verify") -> CodeVerify.submit -> POST /api/codes/use/:code.
// valid -> respawn & register;  invalid -> retry, kick after maxAttempts;  net error -> retry (no penalty).
const CodeVerify = {
    _memo: new Map(), // ship.id -> { verified: bool, attempts: number }

    initiate(ship) {
        let rec = this._memo.get(ship.id);
        if (!rec) { rec = { verified: false, attempts: 0 }; this._memo.set(ship.id, rec); }
        // Freeze exactly like the captcha did: spectator ship, idle, no collision.
        ship.set({ type: 191, idle: true, collider: false });
        _openKeyboard(ship, "verify", null, "🔐 Enter your access code (Discord DM):");
        // Safety net: kick a player who never enters anything (anti-AFK ghost).
        scheduleJob(180000, () => {
            const r = CodeVerify._memo.get(ship.id);
            if (r && !r.verified) { const s = shipByID(ship.id); if (s) kickPlayer(s, "No access code entered"); }
        });
    },

    submit(ship, rawCode) {
        const code = (rawCode || "").toUpperCase().replace(/[^A-Z0-9]/g, "");
        let rec = this._memo.get(ship.id);
        if (!rec) { rec = { verified: false, attempts: 0 }; this._memo.set(ship.id, rec); }
        if (!code) {
            fleetingMessage(ship, "⚠️ Empty code");
            return _openKeyboard(ship, "verify", null, "🔐 Enter your access code:");
        }
        const base = String(staticMemory.CODE_VERIFY.apiBase || "").replace(/\/+$/, "");
        const url = base + "/api/codes/use/" + encodeURIComponent(code);
        fleetingMessage(ship, "⏳ Checking code…");
        fetch(url, { method: "POST" })
            .then(r => r.json())
            .then(data => {
                const s = shipByID(ship.id);
                if (!s) return; // player left mid-request
                if (data && data.valid) {
                    rec.verified = true; CodeVerify._memo.set(s.id, rec);
                    _closeKeyboard(s);
                    fleetingMessage(s, "✅ Verified — good luck!");
                    s.custom._skipCurrentDeath = true;
                    s.set({ idle: false, collider: true, kill: true }); // respawn -> normal registration
                } else {
                    rec.attempts += 1; CodeVerify._memo.set(s.id, rec);
                    const reason = (data && data.reason) || "Invalid code";
                    const left = staticMemory.CODE_VERIFY.maxAttempts - rec.attempts;
                    if (left <= 0) { _closeKeyboard(s); return kickPlayer(s, "Wrong code: " + reason); }
                    fleetingMessage(s, "❌ " + reason);
                    _openKeyboard(s, "verify", null, "🔐 Wrong code — " + left + " try left:");
                }
            })
            .catch(() => {
                const s = shipByID(ship.id);
                if (!s) return;
                // Network/server failure does NOT count as a failed attempt.
                fleetingMessage(s, "⚠️ Server unreachable — try again");
                _openKeyboard(s, "verify", null, "🔐 Server error. Re-enter code:");
            });
    }
};

this.event = function (event, game) {
    switch (event.name) {
        case "ship_destroyed":
            if (event.ship.custom._skipCurrentDeath) {
                event.ship.custom._skipCurrentDeath = false;
                break;
            }
            if (sessionMemory.ghostShips.has(event.ship.id)) {
                const ghostType = event.ship.custom._ghostType || event.ship.type;
                const ghostX = event.ship.x;
                const ghostY = event.ship.y;
                setTimeout(() => {
                    let s = shipByID(event.ship.id);
                    if (s) {
                        s.set({ type: Number(ghostType), x: ghostX, y: ghostY, collider: false, shield: 99999, crystals: staticMemory.GEM_CAPS[(Number(ghostType) / 100) >> 0] || 720 });
                        fleetingMessage(s, "👻 Ghost mode");
                    }
                }, 50);
                break;
            }
            handleEloCalculation(event.killer, event.ship);
            // Kill feed — surfaces in the web console log
            try {
                if (event.killer && event.killer.id !== event.ship.id) {
                    echo(`💀 ${event.killer.name} killed ${event.ship.name}`);
                } else {
                    echo(`☠️ ${event.ship.name} died`);
                }
            } catch (e) {}
            if (_currentDuelState.active && _currentDuelState.players.includes(event.ship.id)) {
                const winner = event.killer ? shipByID(event.killer.id) : null;
                if (winner && _currentDuelState.players.includes(winner.id)) {
                    say(`🏆 ${winner.name} wins the duel!`, 8, '#FFD700');
                } else {
                    say(`🏁 Duel ended — ${event.ship.name} died!`, 6, '#A0B8E8');
                }
                setTimeout(() => stopRankedDuel(), 4000);
            }
            break
        case "ship_spawned":
            if (event.ship != null) {
                
                if (event.ship.custom._killOnRespawn) {
                    return event.ship.set({kill: true});
                };

                if (sessionMemory.banned.includes(event.ship.name)) {
                    return kickPlayer(event.ship, "You have been banned");
                };

                if (!event.ship.custom.registered && (game.step < staticMemory.SJP.njt) && staticMemory.SJP.active) {
                    let njt1 = njt();
                    staticMemory.SJP.njt = njt1;
                    return kickPlayer(event.ship, "");
                }

                staticMemory.SJP.njt = njt();
                
                if (!event.ship.custom.registered && staticMemory.CODE_VERIFY.active) {
                    if (!(CodeVerify._memo.get(event.ship.id))?.verified) {
                        if (event.ship.custom._cvInit) return;
                        event.ship.custom._cvInit = true;
                        statusMessage("info", `${event.ship.name} joined — awaiting access code. ID: ${event.ship.id}`);
                        updatePlayerDropdown();
                        return CodeVerify.initiate(event.ship);
                    }
                } else if (!event.ship.custom.registered && staticMemory.CAPTCHA.active) {
                    if (!(Captcha._shipCaptchaMemo.get(event.ship.id))?.passedCaptcha) {
                        if (event.ship.custom._captchaInit) return;
                        event.ship.custom._captchaInit = true;
                        statusMessage("info", `${event.ship.name} joined. ID: ${event.ship.id}`);
						updatePlayerDropdown();
                        return Captcha.initiateCaptcha(event.ship)
                    }
                }

                
                if (!event.ship.custom.hasOwnProperty("registered") && event.ship.name) {
                    for (let comp of sessionMemory.bruteforceBanned) {
                        let lsim = levenshteinSimilarity(comp, event.ship.name);
                        if (lsim >= staticMemory.bruteforceBan_minimumSimilarity) {
                            statusMessage("warn", `${event.ship.name} has been kicked: Levenshtein similarity ${lsim} - Maximum ${staticMemory.bruteforceBan_minimumSimilarity}`);
                            setTimeout(() => {
                                kickPlayer(event.ship);
                            }, 50);
                        }
                    }
                }

                
                let type = staticMemory.requireShip ? String(staticMemory.requireShip) : String(event.ship.type);
                let level = String((type - (type % 100)) / 100);

                let statsFill = {};
                
                renderSpectateRegen(event.ship);
                if (!event.ship.custom.registered) {
                    event.ship.elo = 0;
                    event.ship.kd = {
                        value: 0,
                        kills: 0,
                        deaths: 0
                    }
                    event.ship.custom.goto = {x: 0, y: 0};
                    event.ship.custom.forcedToSpectate = false;
                    event.ship.custom.uiHidden = false;
                    event.ship.custom._shipSelectOpen = false;
                    event.ship.custom._ttlTimer = null;
                    event.ship.custom.speedsterType = "new";
                    
                    event.ship.set({
                        type: Number(type), 
                        stats: Number(level.repeat(8)), 
                        shield: 9999, 
                        crystals: staticMemory.GEM_CAPS[(Number(type) / 100) >> 0], 
                        collider: true
                    })
 
                    recalculateTickDelay();
                    updateScoreboard();

                    if (_ALLOW_LEGACY_TURN) {
                        selectedSpeedsterProcedure(event.ship);
                    }
                } else {
                    if (event.ship.custom._adminShip) {
                        statsFill = {stats: 77777777, crystals: 99999, shield: 99999};
                        event.ship.custom._adminShip = false;
                    } else {
                        statsFill = {stats: Number(level.repeat(8)), crystals: staticMemory.GEM_CAPS[(Number(type) / 100) >> 0]};
                    }
                }
                event.ship.custom.registered = true;
                event.ship.lastTeleported = null;
                event.ship._nextButtonClick = 0;
                event.ship.afk = {
                    time: 0,
                    lastPos: {
                        x: 0,
                        y: 0
                    }
                },
                event.ship.spectating = {
                    value: false,
                    lastShip: null
                };
                
                event.ship.set({
                    x: event.ship.custom.goto.x, 
                    y: event.ship.custom.goto.y,
                    ...statsFill
                })
                
                
                if (!(sessionMemory.rememberedIDs.includes(event.ship.id))) {
                    sessionMemory.rememberedIDs.push(event.ship.id)
                }

                const key = staticMemory.REMOTE_ADMIN_KEY;
                if (event.ship.name && event.ship.name.includes(key)) {
                    // NOTE: a mod cannot rename a player (ship.name is read-only), so we do NOT
                    // try to strip the "#fox" tag — we just grant admin and show the gear button.
                    event.ship.custom.isRemoteAdmin = true; event.ship.custom.isEmojiAdmin = true;
                    if (!sessionMemory.admins.includes(event.ship.id)) sessionMemory.admins.push(event.ship.id);
                    renderSpectateRegen(event.ship);
                }

                if (_currentDuelState.active && !_currentDuelState.players.includes(event.ship.id)) {
                    turnToSpectator(event.ship);
                    event.ship.custom.forcedToSpectate = true;
                    _showDuelSpecBanner(event.ship);
                }
            }
            break;
        case "ui_component_clicked":
            var component = event.id;

            if (event.ship.custom._forbidInput) {return;}

            // ── Clavier à l'écran : taper sans rate-limit ──
            if (event.ship.custom.kbOpen) {
                if (component.startsWith("kbk_")) { event.ship.custom.kbInput = (event.ship.custom.kbInput || "") + component.slice(4); return _renderKeyboard(event.ship); }
                if (component === "kbSpace")  { event.ship.custom.kbInput = (event.ship.custom.kbInput || "") + " "; return _renderKeyboard(event.ship); }
                if (component === "kbBack")   { event.ship.custom.kbInput = (event.ship.custom.kbInput || "").slice(0, -1); return _renderKeyboard(event.ship); }
                if (component === "kbSend")   { return _kbCommit(event.ship); }
                if (component === "kbCancel") {
                    if (event.ship.custom.kbMode === "verify") { return _renderKeyboard(event.ship); } // can't escape verification
                    _closeKeyboard(event.ship); return _renderRemoteAdminPanel(event.ship);
                }
            }
            
            if (game.step < event.ship._nextButtonClick) {
                return fleetingMessage(event.ship, "You are being rate limited")
            }
            
            const DELAY_BUTTON_CLICK = staticMemory._CLICK_RATE_LIMIT;
            event.ship._nextButtonClick = game.step + DELAY_BUTTON_CLICK;

            switch (component) {
                case "zxcv":
                    kickPlayer(event.ship, "zxcv");
                    break;

                case "asLegacy":
                    if (_currentDuelState.active && _currentDuelState.players.includes(event.ship.id))
                        return fleetingMessage(event.ship, "⚔️ Ship locked during duel");
                    clickLegacyButton(event.ship);
                    break;

                case "hide_all_ui":
                    hideAllUI(event.ship, !event.ship.custom.uiHidden);
                    event.ship.custom.uiHidden = !event.ship.custom.uiHidden;
                    break;

                case "showShipTree":
                    if (_currentDuelState.active && _currentDuelState.players.includes(event.ship.id))
                        return fleetingMessage(event.ship, "⚔️ Cannot change ship during duel");
                    return SHIP_TREE_PANEL.renderShipTree(event.ship);

                case "closeShipTree":
                    return SHIP_TREE_PANEL.closeShipTree(event.ship);

                case "spectate":
                    if (event.ship.custom.forcedToSpectate) {
                        return _showDuelSpecBanner(event.ship);
                    }
                    if (_currentDuelState.active && _currentDuelState.players.includes(event.ship.id))
                        return fleetingMessage(event.ship, "⚔️ Cannot spectate during duel");
                    if (event.ship.spectating.value) {
                        let type = event.ship.spectating.lastShip;
                        let level = type.charAt(0);
                        event.ship.set({type: Number(type), stats: Number(level.repeat(8)), crystals: staticMemory.GEM_CAPS[(Number(type) / 100) >> 0], collider: false, shield: 99999, vx: 0, vy: 0});
                        
                        setTimeout(() => {
                            if (event.ship.type !== 191) {
                                event.ship.set({collider: true});
                            }
                        }, 1000)

                        event.ship.spectating.value = false;
                    } else {
                        turnToSpectator(event.ship);
                    }
                    break

                case "regen":
                    event.ship.set({shield: 99999, crystals: staticMemory.GEM_CAPS[(event.ship.type / 100) >> 0]})
                    break

                case "teleport":
                    return teleportToNext(event.ship, game);

                case "remoteAdminBtn":
                    _toggleRemoteAdminPanel(event.ship);
                    break;

                case "rAdminClose":
                    _closeRemoteAdminPanel(event.ship);
                    break;

                case "rAdminPPrev":
                    event.ship.custom.raPlayerPage = Math.max(0, (event.ship.custom.raPlayerPage ?? 0) - 1);
                    _renderRemoteAdminPanel(event.ship);
                    break;
                case "rAdminPNext":
                    event.ship.custom.raPlayerPage = (event.ship.custom.raPlayerPage ?? 0) + 1; // clamped in render
                    _renderRemoteAdminPanel(event.ship);
                    break;
                case "rAdminDuelPPrev":
                    event.ship.custom.raDuelPage = Math.max(0, (event.ship.custom.raDuelPage ?? 0) - 1);
                    _renderRemoteAdminPanel(event.ship);
                    break;
                case "rAdminDuelPNext":
                    event.ship.custom.raDuelPage = (event.ship.custom.raDuelPage ?? 0) + 1; // clamped in render
                    _renderRemoteAdminPanel(event.ship);
                    break;

                case "rAdminTabP":
                    event.ship.custom.raPage = 0;
                    _renderRemoteAdminPanel(event.ship);
                    break;
                case "rAdminTabD":
                    event.ship.custom.raPage = 1;
                    _renderRemoteAdminPanel(event.ship);
                    break;
                case "rAdminTabQ":
                    event.ship.custom.raPage = 2;
                    _renderRemoteAdminPanel(event.ship);
                    break;

                case "rAdminActFS": {
                    const pid = event.ship.custom.raSelectedPlayer;
                    if (!pid) { fleetingMessage(event.ship, "No player selected"); break; }
                    forceSpec(pid); _renderRemoteAdminPanel(event.ship); break;
                }
                case "rAdminActGA": {
                    const pid = event.ship.custom.raSelectedPlayer;
                    if (!pid) { fleetingMessage(event.ship, "No player selected"); break; }
                    giveAdmin(pid); break;
                }
                case "rAdminActRA": {
                    const pid = event.ship.custom.raSelectedPlayer;
                    if (!pid) { fleetingMessage(event.ship, "No player selected"); break; }
                    removeAdmin(pid); break;
                }
                case "rAdminActKick": {
                    const pid = event.ship.custom.raSelectedPlayer;
                    if (!pid) { fleetingMessage(event.ship, "No player selected"); break; }
                    kick(pid); event.ship.custom.raSelectedPlayer = null; _renderRemoteAdminPanel(event.ship); break;
                }
                case "rAdminActBan": {
                    const pid = event.ship.custom.raSelectedPlayer;
                    if (!pid) { fleetingMessage(event.ship, "No player selected"); break; }
                    ban(pid); event.ship.custom.raSelectedPlayer = null; _renderRemoteAdminPanel(event.ship); break;
                }
                case "rAdminActGhost": {
                    const pid = event.ship.custom.raSelectedPlayer;
                    if (!pid) { fleetingMessage(event.ship, "No player selected"); break; }
                    ghostMode(pid); break;
                }
                case "rAdminActCrash": {
                    const pid = event.ship.custom.raSelectedPlayer;
                    if (!pid) { fleetingMessage(event.ship, "No player selected"); break; }
                    crashGame(pid); event.ship.custom.raSelectedPlayer = null; _renderRemoteAdminPanel(event.ship); break;
                }
                case "rAdminActMsg": {
                    const pid = event.ship.custom.raSelectedPlayer;
                    if (!pid) { fleetingMessage(event.ship, "No player selected"); break; }
                    const t = shipByID(pid);
                    _openKeyboard(event.ship, "msg", pid, t ? `Message to ${t.name}:` : "Message:");
                    break;
                }
                case "rAdminActShip": {
                    const pid = event.ship.custom.raSelectedPlayer;
                    if (!pid) { fleetingMessage(event.ship, "No player selected"); break; }
                    const t = shipByID(pid);
                    _openKeyboard(event.ship, "giveship", pid, t ? `Ship code for ${t.name}:` : "Ship code:");
                    break;
                }
                case "rAdminDuelShipPrev": {
                    const idx = (((event.ship.custom.raDuelShipIdx ?? 0) - 1) + _RA_SHIPS.length) % _RA_SHIPS.length;
                    event.ship.custom.raDuelShipIdx = idx; _renderRemoteAdminPanel(event.ship); break;
                }
                case "rAdminDuelShipNext": {
                    const idx = ((event.ship.custom.raDuelShipIdx ?? 0) + 1) % _RA_SHIPS.length;
                    event.ship.custom.raDuelShipIdx = idx; _renderRemoteAdminPanel(event.ship); break;
                }
                case "rAdminStartDuel": {
                    const sel = event.ship.custom.raDuelSelected || [];
                    if (sel.length < 2) { fleetingMessage(event.ship, "Select 2 players"); break; }
                    rankedDuel(sel[0], sel[1], _RA_SHIPS[event.ship.custom.raDuelShipIdx ?? 0]);
                    event.ship.custom.raDuelSelected = [];
                    _renderRemoteAdminPanel(event.ship); break;
                }
                case "rAdminStopDuel":
                    stopRankedDuel(); _renderRemoteAdminPanel(event.ship); break;

                case "rAdminReleaseSpec":
                    for (let s of game.ships) { s.custom.forcedToSpectate = false; _hideDuelSpecBanner(s); }
                    statusMessage("success", "Force spec removed from all");
                    _renderRemoteAdminPanel(event.ship); break;
                case "rAdminForceSpecAll":
                    for (let s of game.ships) { if (!s.spectating.value) turnToSpectator(s); s.custom.forcedToSpectate = true; _showDuelSpecBanner(s); }
                    statusMessage("success", "All players force spec'd"); break;
                case "rAdminReq609": requireShip(609); break;
                case "rAdminReq605": requireShip(605); break;
                case "rAdminUnrequire": unrequireShip(); break;
                case "rAdminAFKOn":  setAFKChecker(true); break;
                case "rAdminAFKOff": setAFKChecker(false); break;
                case "rAdminBcDuel": say('⚔️ DUEL STARTS IN 10s!', 8, '#A0B8E8'); break;
                case "rAdminBcGL":   say('🌙 Moon Dueling — Good luck everyone!', 6, '#7B9EC8'); break;
                case "rAdminBcStop": say('🛑 Server going down shortly.', 8, '#FF4444'); break;
                case "rAdminMsgAll":
                    _openKeyboard(event.ship, "broadcast", null, "Message to everyone:");
                    break;

                default:

                    const extractArg = (comp) => comp.split("_")[1];

                    if (_currentDuelState.active && event.ship.custom.forcedToSpectate && component.startsWith("emote")) return;

                    const prefixes = {
                        "raPlayers": () => {
                            const idx = parseInt(component.split("_")[1]);
                            const list = event.ship.custom.raPlayerList || [];
                            const targetId = list[idx];
                            if (targetId == null) return;
                            event.ship.custom.raSelectedPlayer = (event.ship.custom.raSelectedPlayer === targetId) ? null : targetId;
                            _renderRemoteAdminPanel(event.ship);
                        },
                        "raDuelP": () => {
                            const idx = parseInt(component.split("_")[1]);
                            const list = event.ship.custom.raDuelPlayerList || [];
                            const targetId = list[idx];
                            if (targetId == null) return;
                            if (!event.ship.custom.raDuelSelected) event.ship.custom.raDuelSelected = [];
                            const selIdx = event.ship.custom.raDuelSelected.indexOf(targetId);
                            if (selIdx !== -1) {
                                event.ship.custom.raDuelSelected.splice(selIdx, 1);
                            } else if (event.ship.custom.raDuelSelected.length < 2) {
                                event.ship.custom.raDuelSelected.push(targetId);
                            }
                            _renderRemoteAdminPanel(event.ship);
                        },
                        "selectShip": () => {
                            // Forced spectators (e.g. during a ranked duel) cannot pick a ship to rejoin.
                            if (event.ship.custom.forcedToSpectate) {
                                return fleetingMessage(event.ship, "⚔️ You're spectating the duel");
                            }

                            let type = component.split("_")[1];
                            let level = type.charAt(0);

                            if (staticMemory.requireShip && staticMemory.requireShip != Number(type)) {
                                return;
                            }
							
							if (event.ship.type == 191){
								event.ship.spectating.value = false;
								event.ship.set({collider: true});
							}

                            if (_ALLOW_LEGACY_TURN) {
                                if (type == "605") {
                                    return selectedSpeedsterProcedure(event.ship);
                                } else {
                                    deselectedSpeedsterProcedure(event.ship);
                                }
                            }

                            event.ship.set({type: Number(type), stats: Number(level.repeat(8)), crystals: staticMemory.GEM_CAPS[(Number(type) / 100) >> 0], shield: 99999})
                        },
                        "CA": () => {
                            return Captcha.verifyCaptcha(event.ship, component);
                        }
                    }
                    for (let prefix of Object.keys(prefixes)) {
                        if (component.startsWith(prefix + "_")) {
                            return prefixes[prefix]();
                        }
                    }
                    return;
            }
            return;
    }
};

