const _hideDuelSpecBanner = (ship) => {
    ship.setUIComponent({ id: "duelSpecBanner", ...NULL_COMPONENT });
};

const _setupDuelPlayer = (ship, shipType = 609, x = 0, y = 0) => {
    ship.custom.forcedToSpectate = false;
    ship.spectating = { value: false, lastShip: null };
    ship.custom.speedsterType = shipType === 609 ? "legacy" : "new";
    // Set type AND position in the SAME call so the type-change respawn can't override the teleport.
    ship.set({ type: shipType, x, y, vx: 0, vy: 0, stats: 66666666, crystals: 720, shield: 99999, collider: true });
    _hideDuelSpecBanner(ship);
    if (shipType === 609 || shipType === 605) selectedSpeedsterProcedure(ship, true);
    else deselectedSpeedsterProcedure(ship);
};

rankedDuel = function(p1Id, p2Id, shipType = 609) {
    const p1 = shipByID(p1Id);
    const p2 = shipByID(p2Id);
    if (!p1) return statusMessage("error", "Ranked Duel: Player 1 not found");
    if (!p2) return statusMessage("error", "Ranked Duel: Player 2 not found");
    if (p1Id === p2Id) return statusMessage("error", "Ranked Duel: Cannot duel yourself");

    if (_currentDuelState.active) {
        for (const oldId of _currentDuelState.players) {
            if (oldId !== p1Id && oldId !== p2Id) {
                const old = shipByID(oldId);
                if (old) {
                    turnToSpectator(old);
                    old.custom.forcedToSpectate = true;
                    old.set({ x: 0, y: 0, vx: 0, vy: 0 });
                    _showDuelSpecBanner(old);
                }
            }
        }
    }

    for (let ship of game.ships) {
        if (ship.id !== p1Id && ship.id !== p2Id) {
            if (!ship.spectating.value) turnToSpectator(ship);
            ship.custom.forcedToSpectate = true;
            ship.set({ x: 0, y: 0, vx: 0, vy: 0 });
            _showDuelSpecBanner(ship);
        }
    }

    _setupDuelPlayer(p1, shipType, -8, 0);
    _setupDuelPlayer(p2, shipType, 8, 0);

    _currentDuelState = { active: true, players: [p1Id, p2Id], shipType };

    say(`⚔️  ${p1.name}  VS  ${p2.name}`, 12, '#A0B8E8');
    setTimeout(() => say('🏁 DUEL START!', 8, '#FFD700'), 4000);

    statusMessage("success", `⚔️ Ranked Duel: ${p1.name} VS ${p2.name}`);
};

stopRankedDuel = function() {
    if (!_currentDuelState.active) {
        return statusMessage("warn", "No ranked duel is currently active");
    }
    for (let ship of game.ships) {
        ship.custom.forcedToSpectate = false;
        _hideDuelSpecBanner(ship);
    }
    _currentDuelState = { active: false, players: [], shipType: 609 };
    say('🏁 Ranked Duel ended!', 5, '#A0B8E8');
    statusMessage("success", "Ranked Duel stopped. Force spec removed from all players.");
};

const _RA_SHIPS       = [609, 605, 615, 616, 613, 614, 101, 201, 202, 301, 302, 303, 304, 401, 402, 403, 404, 405, 406, 501, 502, 503, 504, 505, 506, 507, 601, 602, 603, 604, 606, 607, 617, 618, 619, 620, 621, 622, 623, 624, 625, 626, 627, 628, 629, 630, 631, 632, 633];
const _RA_SHIP_LABELS = ["Legacy Spd","New Spd","🐋 whale-x","🛸 J-20","🚁 DropShip","⚡ ares-xs","Fly","Delta","Trident","Pulse","Side-F","ShadowX1","Y-Def","Vanguard","Mercury","X-Warior","Side-I","Pioneer","Crusader","U-Sniper","FuryStar","T-Warrior","Aetos","ShadowX2","Howler","Bat-Def","Adv-F","Scorpion","Marauder","Condor","Rock-Twr","O-Def", "S17 a-10", "S18 Alien_pr", "S19 falcon", "S20 giant_sh", "S21 godbattl", "S22 Mining P", "S23 scp_2399", "S24 Marauder", "S25 Odyssey", "S26 cruiser", "S27 H2y-xp", "S28 F35_genI", "S29 F-16", "S30 Elicopte", "S31 bombardi", "S32 Space_ca", "S33 Lockheed"];
